#include <stdio.h>
#include <string.h>
int main() {
    int n, t;
    char s[101], key[101];
    scanf("%d", &n);
    scanf("%s", s);
    scanf("%d", &t);
    scanf("%s", key);
    for (int i = 0; i < n; i++) {
        printf("%c", key[i % t]);
    }
    return 0;
}

